/**
 * Echo SVG Icon
 */
function jobportal_icon($icon, $size = 24) {
    echo jobportal_get_icon($icon, $size);
}

/**
 * Render star rating
 */
function jobportal_render_stars($rating, $size = 16) {
    $output = '<div class="jobportal-stars">';
    for ($i = 1; $i <= 5; $i++) {
        if ($i <= $rating) {
            $output .= jobportal_get_icon('star', $size);
        } else {
            $output .= jobportal_get_icon('star-empty', $size);
        }
    }
    $output .= '</div>';
    return $output;
}

/**
 * Get social icon
 */
function jobportal_get_social_icon($network, $size = 20) {
    $network_icons = array(
        'facebook'  => 'facebook',
        'twitter'   => 'twitter',
        'instagram' => 'instagram',
        'linkedin'  => 'linkedin',
        'youtube'   => 'youtube',
        'github'    => 'github',
    );

    if (isset($network_icons[$network])) {
        return jobportal_get_icon($network_icons[$network], $size);
    }

    return '';
}

/**
 * Render social links
 */
function jobportal_render_social_links($size = 20) {
    $networks = array('facebook', 'twitter', 'instagram', 'linkedin', 'youtube', 'github');
    $output = '<div class="jobportal-social-links">';

    foreach ($networks as $network) {
        $url = get_theme_mod('jobportal_social_' . $network, '');
        if (!empty($url)) {
            $output .= sprintf(
                '<a href="%s" target="_blank" rel="noopener noreferrer" class="jobportal-social-link jobportal-social-%s" aria-label="%s">%s</a>',
                esc_url($url),
                esc_attr($network),
                esc_attr(ucfirst($network)),
                jobportal_get_social_icon($network, $size)
            );
        }
    }

    $output .= '</div>';
    return $output;
}

/**
 * Custom comment callback
 */
function jobportal_comment_callback($comment, $args, $depth) {
    $tag = ('div' === $args['style']) ? 'div' : 'li';
    ?>
    <<?php echo $tag; ?> id="comment-<?php comment_ID(); ?>" <?php comment_class(empty($args['has_children']) ? '' : 'parent', $comment); ?>>
        <article id="div-comment-<?php comment_ID(); ?>" class="comment-body">
            <footer class="comment-meta">
                <div class="comment-author vcard">
                    <?php echo get_avatar($comment, $args['avatar_size']); ?>
                    <?php printf('<cite class="fn">%s</cite>', get_comment_author_link($comment)); ?>
                </div>

                <div class="comment-metadata">
                    <a href="<?php echo esc_url(get_comment_link($comment, $args)); ?>">
                        <time datetime="<?php comment_time('c'); ?>">
                            <?php
                            printf(
                                esc_html__('%1$s at %2$s', 'jobportal'),
                                get_comment_date('', $comment),
                                get_comment_time()
                            );
                            ?>
                        </time>
                    </a>
                    <?php edit_comment_link(esc_html__('Edit', 'jobportal'), ' <span class="edit-link">', '</span>'); ?>
                </div>

                <?php if ('0' == $comment->comment_approved) : ?>
                <p class="comment-awaiting-moderation"><?php esc_html_e('Your comment is awaiting moderation.', 'jobportal'); ?></p>
                <?php endif; ?>
            </footer>

            <div class="comment-content">
                <?php comment_text(); ?>
            </div>

            <div class="reply">
                <?php
                comment_reply_link(array_merge($args, array(
                    'add_below' => 'div-comment',
                    'depth'     => $depth,
                    'max_depth' => $args['max_depth'],
                    'before'    => '<span class="reply-link">',
                    'after'     => '</span>',
                )));
                ?>
            </div>
        </article>
    <?php
}
